"use client";


import Link from "next/link";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";
import {
  LayoutDashboard,
  FolderKanban,
  PlayCircle,
  Puzzle,
  Settings,
  ShieldAlert,
} from "lucide-react";

const navigation = [
  { name: "Platform Overview", href: "/", icon: LayoutDashboard },
  { name: "AI QA Command Center", href: "/qa-command-center", icon: ShieldAlert },
  { name: "Projects", href: "/projects", icon: FolderKanban },
  { name: "Runs Explorer", href: "/runs", icon: PlayCircle },
  { name: "Plugin Catalog", href: "/plugins", icon: Puzzle },
  { name: "Settings", href: "/settings", icon: Settings },
];

export function Sidebar() {
  const pathname = usePathname();

  return (
    <div className="flex h-full w-64 flex-col border-r bg-card">
      <div className="flex h-16 items-center border-b px-6">
        <h1 className="text-xl font-bold">UTP Dashboard</h1>
      </div>
      <nav className="flex-1 space-y-1 p-4">
        {navigation.map((item) => {
          const isActive = pathname === item.href;
          return (
            <Link
              key={item.name}
              href={item.href}
              className={cn(
                "flex items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium transition-colors",
                isActive
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:bg-accent hover:text-accent-foreground"
              )}
            >
              <item.icon className="h-5 w-5" />
              {item.name}
            </Link>
          );
        })}
      </nav>
      <div className="border-t p-4">
        <div className="text-xs text-muted-foreground">
          Universal Testing Platform v2.2.0
        </div>
      </div>
    </div>
  );
}
